import RegisterPage from './pages/RegisterPage';
import HomePage from './pages/HomePage'
import LoginPage from './pages/LoginPage'
import SearchPage from './pages/SearchPage';
import NewsstandPage from './pages/NewsstandPage';
import HeadlinesPage from './pages/HeadlinesPage';
import ClippingsPage from './pages/ClippingsPage';
import { Routes, Route } from 'react-router-dom';
import Navbar from './components/Navbar';
import { AuthProvider } from './context/AuthContext';
import { ThemeProvider } from './context/ThemeContext';

function App() {
  return (
    <ThemeProvider>
      <AuthProvider>
        <Navbar />
        <Routes>
          <Route path="/" element={<HomePage />} />
          <Route path="/login" element={<LoginPage />} />
          <Route path="/register" element={<RegisterPage />} />
          <Route path="/search" element={<SearchPage />} />
          <Route path="/newsstand" element={<NewsstandPage />} />
          <Route path="/headlines" element={<HeadlinesPage />} />
          <Route path="/clippings" element={<ClippingsPage />} />
        </Routes>
      </AuthProvider>
    </ThemeProvider>
  );
}

export default App;
